def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[1]
    slide_width = prs.slide_width
    slide_height = prs.slide_height
    textboxes = [shape for shape in slide.shapes if shape.has_text_frame]
    for shape in textboxes:
        if 'Important Note' in shape.text:
            # Check if the bounding box is in bottom right
            # We'll define bottom right as: left > 60% width, top > 70% height
            left, top, width, height = shape.left, shape.top, shape.width, shape.height
            if left > 0.6 * slide_width and top > 0.7 * slide_height:
                return "Text box is correctly positioned in bottom right.", 1.0
            elif left > 0.5 * slide_width and top > 0.6 * slide_height:
                return "Text box is in lower right quadrant, but not strictly bottom right.", 0.7
            else:
                return "Text box is not in bottom right quadrant.", 0.0
    return "No text box with 'Important Note' found on slide 2.", 0.0
